// Parse Slack interactive payload
const body = $input.first().json.body;

// Slack sends form-encoded payload
let payload;
if (typeof body === 'string') {
  // URL decode and parse
  const decoded = decodeURIComponent(body.replace('payload=', ''));
  payload = JSON.parse(decoded);
} else if (body.payload) {
  payload = JSON.parse(body.payload);
} else {
  payload = body;
}

const action = payload.actions?.[0];
if (!action) {
  return [{ json: { error: 'No action found in payload' } }];
}

const result = {
  action_id: action.action_id,
  audit_id: action.value,
  user_id: payload.user?.id,
  user_name: payload.user?.name,
  channel_id: payload.channel?.id,
  response_url: payload.response_url,
  trigger_id: payload.trigger_id
};

return [{ json: result }];

// Generate response message for Slack
const actionId = $('Parse Slack Payload').first().json.action_id;
const audit = $input.first().json;
const userName = $('Parse Slack Payload').first().json.user_name || 'User';

let message;
let emoji;

switch (actionId) {
  case 'approve_all':
    message = `All ${audit.approved_count} items approved by ${userName}. PRD generation will begin shortly.`;
    emoji = ':white_check_mark:';
    break;
  case 'approve_critical_high':
    message = `${audit.approved_count} critical/high items approved by ${userName}. PRD generation will begin shortly.`;
    emoji = ':ballot_box_with_check:';
    break;
  case 'defer':
    message = `Audit deferred to next week by ${userName}.`;
    emoji = ':fast_forward:';
    break;
  default:
    message = `Action processed: ${actionId}`;
    emoji = ':gear:';
}

const responseBlock = {
  replace_original: true,
  blocks: [
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `${emoji} *Speed Audit Update*\n\n${message}\n\n_Week of ${audit.audit_date} | ${audit.total_count} total items_`
      }
    },
    {
      type: 'context',
      elements: [
        {
          type: 'mrkdwn',
          text: `Updated at <!date^${Math.floor(Date.now() / 1000)}^{date_short_pretty} at {time}|${new Date().toISOString()}>`
        }
      ]
    }
  ]
};

return [{
  json: {
    response_url: $('Parse Slack Payload').first().json.response_url,
    response_body: responseBlock,
    should_generate_prd: actionId !== 'defer' && audit.approved_count > 0,
    audit_id: audit.id
  }
}];

// Generate PRD JSON for Ralph
const items = $input.all().map(i => i.json);
const auditId = $('Generate Response').first().json.audit_id;
const today = new Date().toISOString().split('T')[0];

// Generate acceptance criteria based on issue type
function getAcceptanceCriteria(item) {
  const baseAc = item.acceptance_criteria || [];
  const typeAc = {
    'blocking_script': [
      'All blocking scripts have defer or async attribute',
      'LCP improves by >100ms',
      'No functionality regression'
    ],
    'large_image': [
      'Images are properly sized for viewport',
      'Total page weight reduces',
      'Image quality remains acceptable'
    ],
    'no_lazy_load': [
      'Below-fold images have loading="lazy"',
      'Above-fold images remain eager',
      'Initial load time improves'
    ],
    'unoptimized_image': [
      'Images converted to WebP format',
      'Fallbacks provided for older browsers',
      'File size reduces by >30%'
    ],
    'no_preconnect': [
      'Preconnect hints added for external domains',
      'TTFB improves for external resources'
    ],
    'unused_js': [
      'Unused JavaScript removed or deferred',
      'Bundle size reduces',
      'No functionality regression'
    ],
    'unused_css': [
      'Unused CSS removed or loaded asynchronously',
      'Critical CSS inlined if needed',
      'Styles render correctly'
    ],
    'main_thread_work': [
      'Long tasks broken up',
      'Main thread blocking time reduces',
      'INP improves'
    ],
    'long_task': [
      'JavaScript execution time reduces',
      'Tasks split using requestIdleCallback or similar',
      'TBT improves'
    ]
  };

  return [...baseAc, ...(typeAc[item.issue_type] || ['Fix verified by re-running PageSpeed'])];
}

// Build PRD structure
const prd = {
  project: `IAML Speed Optimization - Week of ${today}`,
  branchName: `feature/speed-opt-${today.replace(/-/g, '')}`,
  auditId: auditId,
  stories: items.map((item, index) => ({
    id: item.item_code,
    title: item.title,
    description: item.description + (item.fix_suggestion ? `\n\nSuggested fix: ${item.fix_suggestion}` : ''),
    priority: item.severity === 'critical' ? 1 : (item.severity === 'high' ? 2 : (item.severity === 'medium' ? 3 : 4)),
    files: item.affected_files || (item.file_path ? [item.file_path] : []),
    context: item.page_url ? `Affects: ${item.page_url}` : '',
    acceptance: getAcceptanceCriteria(item),
    passes: false,
    severity: item.severity,
    estimatedImpact: item.estimated_impact
  }))
};

return [{ json: { prd: prd, prdString: JSON.stringify(prd, null, 2) } }];

